import { type, type JsonSchema, type Type } from "arktype"
import { jsonSchemaToType } from "./json.ts"

export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return undefined

	const thenSchema = "then" in jsonSchema ? jsonSchema.then : undefined
	const elseSchema = "else" in jsonSchema ? jsonSchema.else : undefined
	// 'if' without 'then' or 'else' imposes no constraints
	if (thenSchema === undefined && elseSchema === undefined) return undefined

	const ifValidator = jsonSchemaToType(jsonSchema.if!)
	const thenValidator =
		thenSchema === undefined ? undefined : jsonSchemaToType(thenSchema)
	const elseValidator =
		elseSchema === undefined ? undefined : jsonSchemaToType(elseSchema)

	const jsonSchemaIfThenElseValidator = (data: unknown, ctx: Traversal) => {
		// evaluate 'if' silently, i.e. without surfacing any of its own errors
		if (ifValidator.allows(data)) {
			if (!thenValidator) return true
			return thenValidator.allows(data) ?
					true
				:	ctx.reject({
						expected: `${thenValidator.description}, since data matches 'if' schema`,
						actual: printable(data)
					})
