		return elseValidator.allows(data) ?
				true
			:	ctx.reject({
					expected: `${elseValidator.description}, since data doesn't match 'if' schema`,
					actual: printable(data)
				})
	}

	return type.unknown.narrow(jsonSchemaIfThenElseValidator)
}

