}

const defsStack: DefsContext[] = []

const refPattern = /^#\/\$defs\/([^/]+)$/

const resolveRef = (ref: string): Type => {
	const match = refPattern.exec(ref)
	if (!match) throwParseError(writeJsonSchemaInvalidRefMessage())

